import React, { useEffect, useState } from "react";
import API from "../services/api";
import Navbar from "../components/Navbar";

function MedicalRecords() {
  const role = localStorage.getItem("role");
  const isAdmin = role === "ADMIN";

  const [records, setRecords] = useState([]);
  const [animals, setAnimals] = useState([]);
  const [loading, setLoading] = useState(true);
  const [editingId, setEditingId] = useState(null);

  const [formData, setFormData] = useState({
    disease: "",
    treatment: "",
    doctorName: "",
    checkupDate: "",
    healthStatus: "",
    animalId: "",
  });

  useEffect(() => {
    fetchRecords();
    fetchAnimals();
  }, []);

  const fetchRecords = async () => {
    try {
      const res = await API.get("/medical-records");
      setRecords(res.data);
    } catch (error) {
      console.error("Error fetching medical records:", error);
    } finally {
      setLoading(false);
    }
  };

  const fetchAnimals = async () => {
    try {
      const res = await API.get("/animals");
      setAnimals(res.data);
    } catch (error) {
      console.error("Error fetching animals:", error);
    }
  };

  const resetForm = () => {
    setFormData({
      disease: "",
      treatment: "",
      doctorName: "",
      checkupDate: "",
      healthStatus: "",
      animalId: "",
    });
    setEditingId(null);
  };

  const handleChange = (e) => {
    setFormData((prev) => ({
      ...prev,
      [e.target.name]: e.target.value,
    }));
  };

  const handleSubmit = async (e) => {
    e.preventDefault();

    const payload = {
      disease: formData.disease,
      treatment: formData.treatment,
      doctorName: formData.doctorName,
      checkupDate: formData.checkupDate,
      healthStatus: formData.healthStatus,
      animal: formData.animalId ? { id: Number(formData.animalId) } : null,
    };

    try {
      if (editingId) {
        await API.put(`/medical-records/${editingId}`, payload);
        alert("Medical record updated successfully");
      } else {
        await API.post("/medical-records", payload);
        alert("Medical record added successfully");
      }

      resetForm();
      fetchRecords();
    } catch (error) {
      console.error("Error saving medical record:", error);
      const data = error.response?.data;
      if (data && typeof data === "object") {
        alert(Object.values(data)[0]);
      } else {
        alert("Failed to save medical record");
      }
    }
  };

  const handleEdit = (record) => {
    setEditingId(record.id);
    setFormData({
      disease: record.disease || "",
      treatment: record.treatment || "",
      doctorName: record.doctorName || "",
      checkupDate: record.checkupDate || "",
      healthStatus: record.healthStatus || "",
      animalId: record.animal?.id || "",
    });

    window.scrollTo({ top: 0, behavior: "smooth" });
  };

  const handleDelete = async (id) => {
    const confirmDelete = window.confirm("Are you sure you want to delete this medical record?");
    if (!confirmDelete) return;

    try {
      await API.delete(`/medical-records/${id}`);
      alert("Medical record deleted successfully");
      fetchRecords();
    } catch (error) {
      console.error("Error deleting medical record:", error);
      alert("Failed to delete medical record");
    }
  };

  return (
    <div style={styles.page}>
      <Navbar />

      <div style={styles.container}>
        <div style={styles.header}>
          <h1 style={styles.title}>Medical Records Management</h1>
          <p style={styles.subtitle}>
            {isAdmin
              ? "Add, update, view, and manage animal health records from one place."
              : "View all animal medical records."}
          </p>
        </div>

        {isAdmin && (
          <div style={styles.formCard}>
            <h2 style={styles.cardTitle}>
              {editingId ? "Update Medical Record" : "Add New Medical Record"}
            </h2>

            <form onSubmit={handleSubmit} style={styles.formGrid}>
              <input type="text" name="disease" placeholder="Disease / Diagnosis" value={formData.disease} onChange={handleChange} style={styles.input} />
              <input type="text" name="treatment" placeholder="Treatment" value={formData.treatment} onChange={handleChange} style={styles.input} />
              <input type="text" name="doctorName" placeholder="Doctor Name" value={formData.doctorName} onChange={handleChange} style={styles.input} />
              <input type="date" name="checkupDate" value={formData.checkupDate} onChange={handleChange} style={styles.input} />

              <select name="healthStatus" value={formData.healthStatus} onChange={handleChange} style={styles.input}>
                <option value="">Select Health Status</option>
                <option value="Healthy">Healthy</option>
                <option value="Under Treatment">Under Treatment</option>
                <option value="Recovered">Recovered</option>
                <option value="Critical">Critical</option>
              </select>

              <select name="animalId" value={formData.animalId} onChange={handleChange} style={styles.input}>
                <option value="">Select Animal</option>
                {animals.map((animal) => (
                  <option key={animal.id} value={animal.id}>
                    {animal.name} - {animal.species}
                  </option>
                ))}
              </select>

              <div style={styles.buttonRow}>
                <button type="submit" style={styles.primaryBtn}>
                  {editingId ? "Update Record" : "Add Record"}
                </button>

                {editingId && (
                  <button type="button" style={styles.cancelBtn} onClick={resetForm}>
                    Cancel
                  </button>
                )}
              </div>
            </form>
          </div>
        )}

        <div style={styles.listSection}>
          <h2 style={styles.cardTitle}>Medical Records List</h2>

          {loading ? (
            <p>Loading medical records...</p>
          ) : records.length === 0 ? (
            <p>No medical records found.</p>
          ) : (
            <div style={styles.grid}>
              {records.map((record) => (
                <div key={record.id} style={styles.recordCard}>
                  <h3 style={styles.recordTitle}>{record.animal?.name || "Animal Not Assigned"}</h3>
                  <p><strong>Species:</strong> {record.animal?.species || "-"}</p>
                  <p><strong>Disease:</strong> {record.disease}</p>
                  <p><strong>Treatment:</strong> {record.treatment}</p>
                  <p><strong>Doctor:</strong> {record.doctorName}</p>
                  <p><strong>Checkup Date:</strong> {record.checkupDate}</p>
                  <p><strong>Health Status:</strong> {record.healthStatus}</p>

                  {isAdmin && (
                    <div style={styles.actionRow}>
                      <button style={styles.editBtn} onClick={() => handleEdit(record)}>
                        Edit
                      </button>
                      <button style={styles.deleteBtn} onClick={() => handleDelete(record.id)}>
                        Delete
                      </button>
                    </div>
                  )}
                </div>
              ))}
            </div>
          )}
        </div>
      </div>
    </div>
  );
}

